  cfg_classify: { bg:'Разпознавай какво помръдна (TF.js)', ru:'Распознавать, что шевельнулось (TF.js)', uk:'Розпізнавати, що ворухнулося (TF.js)', en:'Recognize what moved (TF.js)', de:'Erkennen, was sich bewegt hat (TF.js)', fr:'Reconnaître ce qui a bougé (TF.js)', es:'Reconocer qué se movió (TF.js)', 'es-MX':'Reconocer qué se movió (TF.js)', it:'Riconoscere cosa si è mosso (TF.js)', pt:'Reconhecer o que se moveu (TF.js)', ar:'التعرّف على ما تحرّك (TF.js)', hi:'पहचानें कि क्या हिला (TF.js)', ja:'何が動いたか認識（TF.js）', ky:'Эмне кыймылдаганын таануу (TF.js)', 'zh-Hant':'辨識什麼移動了（TF.js）' },
  cfg_classify_hint: { bg:'Ако е изключено: алармира само „движение“, без класификация (по-малко работа).', ru:'Если выключено: предупреждает только о «движении», без классификации (меньше нагрузки).', uk:'Якщо вимкнено: попереджає лише про «рух», без класифікації (менше навантаження).', en:'If off: alerts only on "motion", without classification (less work).', de:'Wenn aus: warnt nur bei „Bewegung“, ohne Klassifizierung (weniger Aufwand).', fr:'Si désactivé : alerte seulement sur « mouvement », sans classification (moins de travail).', es:'Si está apagado: alerta solo de «movimiento», sin clasificación (menos trabajo).', 'es-MX':'Si está apagado: alerta solo de «movimiento», sin clasificación (menos trabajo).', it:'Se disattivato: avvisa solo su «movimento», senza classificazione (meno lavoro).', pt:'Se desligado: alerta apenas «movimento», sem classificação (menos trabalho).', ar:'إذا أُوقف: يُنبّه فقط على «الحركة»، بدون تصنيف (عمل أقل).', hi:'बंद हो तो: केवल «गति» पर अलर्ट, बिना वर्गीकरण (कम काम)।', ja:'オフの場合：分類せず「動き」のみ通知（負荷が軽い）。', ky:'Өчүк болсо: классификациясыз «кыймыл» жөнүндө гана эскертет (азыраак жүк).', 'zh-Hant':'若關閉：僅對「動作」警報，不分類（負擔較小）。' },
  cfg_local_notif: { bg:'Локални нотификации при детекция', ru:'Локальные уведомления при обнаружении', uk:'Локальні сповіщення при виявленні', en:'Local notifications on detection', de:'Lokale Benachrichtigungen bei Erkennung', fr:'Notifications locales à la détection', es:'Notificaciones locales al detectar', 'es-MX':'Notificaciones locales al detectar', it:'Notifiche locali al rilevamento', pt:'Notificações locais na detecção', ar:'إشعارات محلية عند الكشف', hi:'पहचान पर स्थानीय सूचनाएँ', ja:'検知時のローカル通知', ky:'Аныктоодо жергиликтүү билдирүүлөр', 'zh-Hant':'偵測時的本機通知' },
  cfg_cooldown: { bg:'Пауза между сигнали (cooldown)', ru:'Пауза между сигналами (cooldown)', uk:'Пауза між сигналами (cooldown)', en:'Pause between alerts (cooldown)', de:'Pause zwischen Warnungen (Cooldown)', fr:'Pause entre alertes (cooldown)', es:'Pausa entre alertas (cooldown)', 'es-MX':'Pausa entre alertas (cooldown)', it:'Pausa tra gli avvisi (cooldown)', pt:'Pausa entre alertas (cooldown)', ar:'فاصل بين التنبيهات (cooldown)', hi:'अलर्ट के बीच ठहराव (cooldown)', ja:'通知間の待機（クールダウン）', ky:'Сигналдар арасында тыныгуу (cooldown)', 'zh-Hant':'警報之間的暫停（冷卻）' },
