  pair_role_watcher: { bg:'Наблюдаващ (получава известията)', ru:'Наблюдатель (получает уведомления)', uk:'Спостерігач (отримує сповіщення)', en:'Watcher (receives the alerts)', de:'Beobachter (empfängt die Warnungen)', fr:'Observateur (reçoit les alertes)', es:'Observador (recibe las alertas)', 'es-MX':'Observador (recibe las alertas)', it:'Osservatore (riceve gli avvisi)', pt:'Observador (recebe os alertas)', ar:'مراقب (يستقبل التنبيهات)', hi:'प्रहरी (अलर्ट पाता है)', ja:'ウォッチャー（通知を受信）', ky:'Байкоочу (билдирүүлөрдү алат)', 'zh-Hant':'觀察者（接收警報）' },
  pair_key: { bg:'Ключ за двойката (еднакъв на двата телефона)', ru:'Ключ пары (одинаковый на двух телефонах)', uk:'Ключ пари (однаковий на двох телефонах)', en:'Pair key (the same on both phones)', de:'Paarschlüssel (auf beiden Telefonen gleich)', fr:'Clé de paire (identique sur les deux téléphones)', es:'Clave de par (igual en ambos teléfonos)', 'es-MX':'Clave de par (igual en ambos teléfonos)', it:'Chiave di coppia (uguale su entrambi i telefoni)', pt:'Chave de par (igual nos dois telefones)', ar:'مفتاح الزوج (نفسه على الهاتفين)', hi:'पेयर कुंजी (दोनों फ़ोन पर समान)', ja:'ペアキー（両方の電話で同じ）', ky:'Жуп ачкычы (эки телефондо бирдей)', 'zh-Hant':'配對金鑰（兩支手機相同）' },
