let current = detect();

function detect() {
  try { const s = localStorage.getItem(LS_KEY); if (s && STR.save[s] != null) return s; } catch (e) {}
  return DEFAULT_LANG;
}

export function hasLangChosen() {
  try { return !!localStorage.getItem(LS_KEY); } catch (e) { return false; }
}
export function getLang() { return current; }
export function setLang(code) {
  if (STR.save[code] == null) return;
  current = code;
  try { localStorage.setItem(LS_KEY, code); } catch (e) {}
  applyDir();
}
export function isRTL() { return RTL_CODES.indexOf(current) > -1; }
export function applyDir() {
  try {
    document.documentElement.setAttribute('dir', isRTL() ? 'rtl' : 'ltr');
    document.documentElement.setAttribute('lang', current);
  } catch (e) {}
}
export function t(key) {
  const row = STR[key];
  if (!row) return key;
  if (row[current] != null) return row[current];
  if (row[DEFAULT_LANG] != null) return row[DEFAULT_LANG];
  if (row[FALLBACK_LANG] != null) return row[FALLBACK_LANG];
  return key;
}
export function tf(key, ...vals) {
  let s = t(key);
  vals.forEach((v, i) => { s = s.replace(new RegExp('\\{' + i + '\\}', 'g'), String(v)); });
  return s;
}

// Превежда клас от COCO-SSD ('dog', 'cat'…) към локализиран етикет за UI.
const CLASS_KEY = {
  person: 'cls_person', dog: 'cls_dog', cat: 'cls_cat', bird: 'cls_bird',
  horse: 'cls_horse', sheep: 'cls_sheep', cow: 'cls_cow', elephant: 'cls_elephant',
  bear: 'cls_bear', zebra: 'cls_zebra', giraffe: 'cls_giraffe'
};
export function classLabel(cocoClass) {
  const key = CLASS_KEY[cocoClass];
  return key ? t(key) : cocoClass;
}

export { LANGUAGES, languageByCode, DEFAULT_LANG, FALLBACK_LANG };
